mapper.select:
SELECT IP.TBL_INV_PRODUCT_ID as tblInvProductId, IP.CMPY_CD as cmpyCd, IP.AGNT_CD as agntCd, IP.AGNT_NM as agntNm, IP.MTRL_CD as productCd, IP.MTRL_NM as productNm, IP.CURRENT_QTY as currentQty, IP.SAVE_TIME as saveTime, IP.SAVE_USER as saveUser, IP.UPDT_TIME as updtTime, IP.UPDT_USER as updtUser FROM TBL_INV_PRODUCT IP INNER JOIN TBL_MTRL_M MM ON IP.MTRL_CD = MM.MTRL_CD AND IP.CMPY_CD = MM.CMPY_CD AND IP.AGNT_CD = MM.AGNT_CD WHERE 1=1 AND MM.MTO_YN = 'N' -- MTO가 아닌 상품만 조회
AND IP.CMPY_CD = #{cmpyCd}
AND IP.AGNT_CD = #{agntCd}
AND IP.MTRL_CD LIKE '%' + #{productCd} + '%'
AND IP.MTRL_NM LIKE '%' + #{productNm} + '%'
ORDER BY IP.MTRL_CD

mapper.update:
UPDATE TBL_INV_PRODUCT 
SET CURRENT_QTY = #{afterQty},
    UPDT_TIME = GETDATE(),
    UPDT_USER = ISNULL(#{saveUser}, 'SYSTEM')
WHERE CMPY_CD = #{cmpyCd}
  AND AGNT_CD = #{agntCd}
  AND MTRL_CD = #{productCd}
